 35→  // ── Helpers ─────────────────────────────────────────────────────────────────
 36→
 37→  function esc(text) {
 38→    return text
 39→      .replace(/&/g, "&amp;")
 40→      .replace(/</g, "&lt;")
 41→      .replace(/>/g, "&gt;")
 42→      .replace(/"/g, "&quot;");
 43→  }
 44→
 45→  var EXT_TO_LANG = {
 46→    ".ts": "typescript", ".tsx": "typescript", ".js": "javascript", ".jsx": "javascript",
 47→    ".py": "python", ".rs": "rust", ".go": "go", ".rb": "ruby", ".java": "java",
 48→    ".c": "c", ".cpp": "cpp", ".h": "c", ".hpp": "cpp", ".cs": "csharp",
 49→    ".swift": "swift", ".kt": "kotlin", ".sh": "bash", ".bash": "bash",
 50→    ".zsh": "bash", ".fish": "bash", ".yml": "yaml", ".yaml": "yaml",
 51→    ".json": "json", ".toml": "toml", ".xml": "xml", ".html": "html",
 52→    ".css": "css", ".scss": "scss", ".sql": "sql", ".md": "markdown",
 53→    ".dockerfile": "dockerfile", ".tf": "hcl", ".lua": "lua", ".r": "r",
 54→    ".svelte": "html", ".vue": "html",
 55→  };
 56→
 57→  function extname(fp) {
 58→    var m = fp.match(/\.[^/.]+$/);
 59→    return m ? m[0] : "";
 60→  }
 61→
 62→  function basename(fp) {
 63→    return fp.split("/").pop() || fp;
 64→  }
 65→
 66→  function langFromPath(filePath) {
 67→    var ext = extname(filePath).toLowerCase();
 68→    if (EXT_TO_LANG[ext]) return EXT_TO_LANG[ext];
 69→    var base = basename(filePath).toLowerCase();
 70→    if (base === "dockerfile") return "dockerfile";
 71→    if (base === "makefile") return "makefile";
 72→    if (base === "justfile") return "makefile";
 73→    if (base.endsWith(".env")) return "bash";
 74→    return "";
 75→  }
 76→
 77→  function fileLink(filePath, commitSha) {
 78→    if (!repoUrl) return '<span class="file-path">' + esc(filePath) + "</span>";
 79→    var rel = filePath;
 80→    var repoName = repoUrl.split("/").pop() || "";
 81→    var idx = rel.indexOf("/" + repoName + "/");
 82→    if (idx !== -1) {
 83→      rel = rel.slice(idx + repoName.length + 2);
 84→    }
 85→    var url = repoUrl + "/blob/" + commitSha + "/" + rel;
 86→    return '<a class="file-link" href="' + esc(url) + '" target="_blank" rel="noopener">' + esc(filePath) + "</a>";
 87→  }
 88→
 89→  function shortPath(filePath) {
 90→    var parts = filePath.split("/");
 91→    if (parts.length <= 3) return filePath;
 92→    return parts.slice(0, 1).join("/") + "/.../" + parts.slice(-2).join("/");
 93→  }
 94→
 95→  // ── Markdown rendering (marked.js) ──────────────────────────────────────────
 96→
 97→  if (typeof marked !== "undefined") {
 98→    marked.setOptions({
 99→      gfm: true,
100→      breaks: true,
101→      highlight: function (code, lang) {
102→        if (typeof hljs !== "undefined") {
103→          if (lang && hljs.getLanguage(lang)) {
104→            try { return hljs.highlight(code, { language: lang }).value; } catch (e) {}
105→          }
106→          try { return hljs.highlightAuto(code).value; } catch (e) {}
107→        }
108→        return code;
109→      },
110→    });
111→  }
112→
113→  function renderMarkdown(text) {
114→    if (typeof marked !== "undefined") {
115→      try { return marked.parse(text); } catch (e) {}
116→    }
117→    // Fallback: basic escaping with code blocks
118→    var escaped = esc(text);
119→    escaped = escaped.replace(/```(\w*)\n([\s\S]*?)```/g, function (_, lang, code) {
120→      var cls = lang ? ' class="language-' + lang + '"' : "";
121→      return "<pre><code" + cls + ">" + code + "</code></pre>";
122→    });
123→    escaped = escaped.replace(/`([^`]+)`/g, "<code>$1</code>");
124→    escaped = escaped.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>");
125→    var parts = escaped.split(/(<pre>[\s\S]*?<\/pre>)/);
126→    for (var i = 0; i < parts.length; i++) {
127→      if (!parts[i].startsWith("<pre>")) {
128→        parts[i] = parts[i].replace(/\n/g, "<br>\n");
129→      }
130→    }
131→    return parts.join("");
132→  }
133→
134→  // ── Diff rendering ──────────────────────────────────────────────────────────
135→
136→  function renderDiff(oldStr, newStr, filePath, lang) {
137→    if (typeof Diff === "undefined") {
138→      return '<pre><code class="language-diff">' + esc(newStr) + "</code></pre>";
139→    }
140→    var patch = Diff.createTwoFilesPatch(filePath, filePath, oldStr, newStr, "", "");
141→    var lines = patch.split("\n");
142→    var startIdx = 0;
143→    for (var i = 0; i < lines.length; i++) {
144→      if (lines[i].startsWith("@@")) { startIdx = i; break; }
145→    }
146→    var out = [];
147→    var oldLine = 0, newLine = 0;
148→    for (var i = startIdx; i < lines.length; i++) {
149→      var line = lines[i];
150→      if (line.startsWith("@@")) {
151→        var match = line.match(/@@ -(\d+)/);
152→        if (match) { oldLine = parseInt(match[1], 10) - 1; newLine = oldLine; }
153→        var matchNew = line.match(/\+(\d+)/);
154→        if (matchNew) newLine = parseInt(matchNew[1], 10) - 1;
155→        out.push('<tr class="diff-hunk"><td class="diff-ln"></td><td class="diff-ln"></td><td class="diff-marker"></td><td>' + esc(line) + "</td></tr>");
156→      } else if (line.startsWith("+")) {
157→        newLine++;
158→        out.push('<tr class="diff-add"><td class="diff-ln"></td><td class="diff-ln">' + newLine + '</td><td class="diff-marker">+</td><td>' + esc(line.slice(1)) + "</td></tr>");
159→      } else if (line.startsWith("-")) {
160→        oldLine++;
161→        out.push('<tr class="diff-del"><td class="diff-ln">' + oldLine + '</td><td class="diff-ln"></td><td class="diff-marker">-</td><td>' + esc(line.slice(1)) + "</td></tr>");
162→      } else if (line.startsWith("\\")) {
163→        continue;
164→      } else {
165→        oldLine++; newLine++;
166→        out.push('<tr class="diff-ctx"><td class="diff-ln">' + oldLine + '</td><td class="diff-ln">' + newLine + '</td><td class="diff-marker"> </td><td>' + esc(line.slice(1) || "") + "</td></tr>");
167→      }
168→    }
169→    var langAttr = lang ? ' data-lang="' + lang + '"' : "";
170→    return '<table class="diff-table"' + langAttr + ">" + out.join("\n") + "</table>";
171→  }
172→
173→  // ── Tool icons (inline SVG) ─────────────────────────────────────────────────
174→
