176→    Bash: "terminal", Read: "file", Edit: "edit", Write: "file-plus",
177→    Grep: "search", Glob: "search", Task: "cpu", WebFetch: "globe",
178→    WebSearch: "globe", EnterPlanMode: "map", AskUserQuestion: "help-circle",
179→  };
