187→    cpu: '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="4" y="4" width="16" height="16" rx="2" ry="2"/><rect x="9" y="9" width="6" height="6"/><line x1="9" y1="1" x2="9" y2="4"/><line x1="15" y1="1" x2="15" y2="4"/><line x1="9" y1="20" x2="9" y2="23"/><line x1="15" y1="20" x2="15" y2="23"/><line x1="20" y1="9" x2="23" y2="9"/><line x1="20" y1="14" x2="23" y2="14"/><line x1="1" y1="9" x2="4" y2="9"/><line x1="1" y1="14" x2="4" y2="14"/></svg>',
188→    globe: '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="2" y1="12" x2="22" y2="12"/><path d="M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"/></svg>',
189→    map: '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polygon points="1 6 1 22 8 18 16 22 23 18 23 2 16 6 8 2 1 6"/><line x1="8" y1="2" x2="8" y2="18"/><line x1="16" y1="6" x2="16" y2="22"/></svg>',
190→    "help-circle": '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><path d="M9.09 9a3 3 0 0 1 5.83 1c0 2-3 3-3 3"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>',
191→    tool: '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M14.7 6.3a1 1 0 0 0 0 1.4l1.6 1.6a1 1 0 0 0 1.4 0l3.77-3.77a6 6 0 0 1-7.94 7.94l-6.91 6.91a2.12 2.12 0 0 1-3-3l6.91-6.91a6 6 0 0 1 7.94-7.94l-3.76 3.76z"/></svg>',
192→  };
193→
194→  function toolIcon(name) {
195→    var icon = TOOL_ICONS[name] || "tool";
196→    return SVGS[icon] || SVGS.tool;
197→  }
198→
199→  // ── Extract tool result content ─────────────────────────────────────────────
200→
201→  function extractResultContent(block) {
202→    var content = block.content;
203→    if (typeof content === "string") return content;
204→    if (Array.isArray(content)) {
205→      return content
206→        .filter(function (c) { return typeof c === "object" && c.type === "text"; })
207→        .map(function (c) { return c.text || ""; })
208→        .join("\n");
209→    }
210→    return "";
211→  }
212→
213→  // ── Build tool result map ───────────────────────────────────────────────────
214→
215→  function buildToolResultMap(messages) {
216→    var map = {};
217→    for (var i = 0; i < messages.length; i++) {
218→      var msg = messages[i];
219→      if (msg.type !== "user") continue;
220→      var content = msg.message && msg.message.content;
221→      if (!Array.isArray(content)) continue;
222→      for (var j = 0; j < content.length; j++) {
223→        var block = content[j];
224→        if (block.type === "tool_result" && block.tool_use_id) {
225→          map[block.tool_use_id] = block;
226→        }
227→      }
228→    }
229→    return map;
230→  }
231→
232→  // ── Render tool use ─────────────────────────────────────────────────────────
233→
234→  function renderToolUse(block, result, commitSha, subagents, author) {
235→    var name = block.name || "Unknown";
236→    var inp = block.input || {};
237→    var icon = toolIcon(name);
238→    var summaryLabel = "";
239→    var detail = "";
240→
241→    switch (name) {
242→      case "Bash": {
243→        var cmd = inp.command || "";
244→        var desc = inp.description || "";
245→        var cmdLines = cmd.split("\n");
246→        var firstActionLine = "";
247→        for (var i = 0; i < cmdLines.length; i++) {
248→          var trimmed = cmdLines[i].trim();
249→          if (trimmed && !trimmed.startsWith("#")) { firstActionLine = cmdLines[i]; break; }
250→        }
251→        if (!firstActionLine) firstActionLine = cmdLines[0] || "";
252→        var cmdPreview = firstActionLine.length > 80 ? firstActionLine.slice(0, 80) + "..." : firstActionLine;
253→        summaryLabel = desc
254→          ? '<span class="tool-cmd-preview">' + esc(cmdPreview) + '</span><span class="tool-desc">' + esc(desc) + "</span>"
255→          : '<span class="tool-cmd-preview">' + esc(cmdPreview) + "</span>";
256→        detail = '<pre><code class="language-bash">' + esc(cmd) + "</code></pre>";
257→        break;
258→      }
259→      case "Read": {
260→        var fp = inp.file_path || "";
261→        summaryLabel = shortPath(fp);
262→        detail = '<div class="tool-file-header">' + fileLink(fp, commitSha) + "</div>";
263→        break;
264→      }
265→      case "Edit": {
266→        var fp = inp.file_path || "";
267→        var oldStr = inp.old_string || "";
268→        var newStr = inp.new_string || "";
269→        var lang = langFromPath(fp);
270→        var addCount = newStr.split("\n").length;
271→        var delCount = oldStr.split("\n").length;
272→        var badge = '<span class="diff-badge"><span class="diff-badge-add">+' + addCount + '</span> <span class="diff-badge-del">-' + delCount + "</span></span>";
273→        summaryLabel = shortPath(fp) + " " + badge;
274→        detail = '<div class="tool-file-header">' + fileLink(fp, commitSha) + "</div>";
275→        if (oldStr || newStr) {
276→          detail += '<div class="diff-container">' + renderDiff(oldStr, newStr, fp, lang) + "</div>";
277→        }
278→        break;
279→      }
280→      case "Write": {
281→        var fp = inp.file_path || "";
282→        var content = inp.content || "";
283→        var lang = langFromPath(fp);
284→        var lineCount = content.split("\n").length;
285→        summaryLabel = shortPath(fp) + ' <span class="diff-badge"><span class="diff-badge-add">+' + lineCount + "</span></span>";
286→        detail = '<div class="tool-file-header">' + fileLink(fp, commitSha) + "</div>";
287→        var displayContent = content.length > 5000
288→          ? content.slice(0, 5000) + "\n... (" + content.length + " chars total)"
289→          : content;
290→        var cls = lang ? ' class="language-' + lang + '"' : "";
291→        detail += "<pre><code" + cls + ">" + esc(displayContent) + "</code></pre>";
292→        break;
293→      }
294→      case "Grep": {
295→        var pattern = inp.pattern || "";
296→        var path = inp.path || "";
297→        summaryLabel = '"' + esc(pattern) + '"' + (path ? " in " + shortPath(path) : "");
298→        break;
299→      }
300→      case "Glob": {

400→      msg.type === "progress" ||
401→      msg.type === "queue-operation" ||
402→      msg.type === "pr-link" ||
403→      msg.isMeta
404→    ) {
405→      return null;
406→    }
407→
408→    if (msg.type === "assistant") {
409→      var content = msg.message && msg.message.content;
410→      if (!content) return null;
411→
412→      if (typeof content === "string") {
413→        if (!content.trim()) return null;
414→        return { role: "assistant", html: '<div class="msg-item">' + renderMarkdown(content.trim()) + "</div>" };
415→      }
416→
417→      var parts = [];
418→      for (var i = 0; i < content.length; i++) {
419→        var c = content[i];
420→        if (c.type === "thinking" && c.thinking) {
421→          parts.push(renderThinking(c.thinking));
422→        } else if (c.type === "text" && c.text && c.text.trim()) {
423→          parts.push('<div class="msg-text">' + renderMarkdown(c.text.trim()) + "</div>");
424→        } else if (c.type === "tool_use") {
425→          var result = c.id ? toolResultMap[c.id] || null : null;
426→          parts.push(renderToolUse(c, result, commitSha, subagents, author));
427→        }
428→      }
429→
430→      if (parts.length === 0) return null;
431→      return { role: "assistant", html: '<div class="msg-item">' + parts.join("\n") + "</div>" };
432→    }
433→
434→    if (msg.type === "user") {
435→      var content = msg.message && msg.message.content;
436→      if (!content) return null;
437→
438→      if (typeof content === "string") {
439→        if (content.startsWith("<") && !content.startsWith("<!")) return null;
440→        if (!content.trim()) return null;
441→        return { role: "user", html: '<div class="msg-item">' + renderMarkdown(content) + "</div>" };
442→      }
443→
444→      var textParts = [];
445→      for (var i = 0; i < content.length; i++) {
446→        var c = content[i];
447→        if (c.type === "text" && c.text && c.text.trim()) {
448→          if (c.text.startsWith("<local-command") || c.text.startsWith("<command-")) continue;
449→          if (c.text.startsWith("<system-reminder")) continue;
450→          if (c.text.startsWith("<local-command-stdout")) continue;
451→          textParts.push(c.text);
452→        }
453→      }
454→
455→      if (textParts.length === 0) return null;
456→      return { role: "user", html: '<div class="msg-item">' + renderMarkdown(textParts.join("\n").trim()) + "</div>" };
457→    }
458→
459→    if (msg.type === "system") {
460→      var text = typeof msg.message === "string"
461→        ? msg.message
462→        : (msg.message && typeof msg.message.content === "string")
463→          ? msg.message.content
464→          : "";
465→      if (text && !text.startsWith("<")) {
466→        return { role: "system", html: '<details class="system-msg"><summary>System</summary><div class="msg-body">' + renderMarkdown(text) + "</div></details>" };
467→      }
468→    }
469→
470→    return null;
471→  }
472→
473→  // ── Process session (group messages) ────────────────────────────────────────
474→
475→  function processSession(messages, commitSha, author, label, subagents) {
476→    var toolResultMap = buildToolResultMap(messages);
477→    var output = [];
478→    var userNav = [];
479→
480→    if (label) {
481→      output.push('<div class="subagent-label">' + esc(label) + "</div>");
482→    }
483→
484→    // Render all messages
485→    var rendered = [];
486→    for (var mi = 0; mi < messages.length; mi++) {
487→      var msg = messages[mi];
488→      var r;
489→      r = renderMessage(msg, toolResultMap, commitSha, author, subagents);
490→      if (r) {
491→        var text = "";
492→        if (r.role === "user") {
493→          var content = msg.message && msg.message.content;
494→          if (typeof content === "string") {
495→            text = content.trim();
496→          } else if (Array.isArray(content)) {
497→            for (var ci = 0; ci < content.length; ci++) {
498→              var c = content[ci];
499→              if (c.type === "text" && c.text && c.text.trim()) {
500→                if (c.text.startsWith("<")) continue;
501→                text = c.text.trim();
502→                break;
503→              }
504→            }
505→          }
506→        }
507→        rendered.push({ role: r.role, html: r.html, text: text });
508→      }
509→    }
510→
511→    // Group consecutive messages by role
512→    var i = 0;
513→    var userGroupIdx = 0;
514→    while (i < rendered.length) {
515→      var role = rendered[i].role;
516→      var groupItems = [];
517→      var groupText = "";
518→      while (i < rendered.length && rendered[i].role === role) {
519→        groupItems.push(rendered[i].html);
520→        if (!groupText && rendered[i].text && !rendered[i].text.startsWith("[Request interrupted")) {
521→          groupText = rendered[i].text;
522→        }
523→        i++;
524→      }
525→
526→      if (role === "user") {
527→        userGroupIdx++;
528→        turnCounter++;
529→        var id = "turn-" + turnCounter;
530→        var anchor = '<a class="msg-anchor" href="#' + id + '" aria-label="Link to this message">' + LINK_SVG + '</a>';
531→        var preview = groupText
532→          .replace(/\n/g, " ")
533→          .replace(/\s+/g, " ")
534→          .slice(0, 60)
535→          .trim();
536→        if (preview) {
537→          userNav.push({ id: id, preview: preview + (groupText.length > 60 ? "..." : ""), index: userGroupIdx });
538→        }
539→        output.push('<div id="' + id + '" class="msg-group user-group">' + anchor + '<img class="avatar user-avatar" src="https://github.com/' + encodeURIComponent(author) + '.png?size=48" alt="' + esc(author) + '"><div class="msg-group-content">' + groupItems.join("\n") + "</div></div>");
540→      } else if (role === "assistant") {
541→        turnCounter++;
542→        var id = "turn-" + turnCounter;
543→        var anchor = '<a class="msg-anchor" href="#' + id + '" aria-label="Link to this message">' + LINK_SVG + '</a>';
544→        output.push('<div id="' + id + '" class="msg-group assistant-group">' + anchor + '<span class="avatar assistant-avatar">' + CLAUDE_LOGO_SVG + '</span><div class="msg-group-content">' + groupItems.join("\n") + "</div></div>");
545→      } else {
546→        output.push(groupItems.join("\n"));
547→      }
548→    }
549→
550→    return { html: output.join("\n"), userNav: userNav };
551→  }
