553→  // ── Parse bundled JSONL (split on ---SUBAGENT: markers) ─────────────────────
554→
555→  function parseBundledJsonl(text) {
556→    // Split on ---SUBAGENT:id--- only when it appears on its own line
557→    // (not inside JSON strings where it may appear as content)
558→    var parts = text.split(/\n---SUBAGENT:/);
559→    var mainLines = parseJsonlLines(parts[0]);
560→    var subagents = {};
561→
562→    for (var p = 1; p < parts.length; p++) {
563→      var chunk = parts[p];
564→      var nlIdx = chunk.indexOf("---\n");
565→      if (nlIdx === -1) continue;
566→      var agentId = chunk.slice(0, nlIdx).trim();
567→      // Validate agentId looks like a real ID (alphanumeric/hyphens/underscores, not prose)
568→      if (!agentId || agentId.length > 80 || /\s/.test(agentId)) continue;
569→      var agentContent = chunk.slice(nlIdx + 4);
570→      var saLines = parseJsonlLines(agentContent);
571→
572→      // Extract description from first non-XML user message
573→      var desc = agentId;
574→      for (var si = 0; si < saLines.length; si++) {
575→        var sl = saLines[si];
576→        if (sl.type === "user" && sl.message && sl.message.content) {
577→          var c = sl.message.content;
578→          if (typeof c === "string" && !c.startsWith("<")) {
579→            desc = c.slice(0, 80);
580→            break;
581→          }
582→          if (Array.isArray(c)) {
583→            for (var bi = 0; bi < c.length; bi++) {
584→              if (c[bi].type === "text" && c[bi].text && !c[bi].text.startsWith("<")) {
585→                desc = c[bi].text.slice(0, 80);
586→                break;
587→              }
588→            }
589→            if (desc !== agentId) break;
590→          }
591→        }
592→      }
593→      subagents[agentId] = { lines: saLines, desc: desc };
594→    }
595→
596→    return { main: mainLines, subagents: subagents };
597→  }
598→
599→  function parseJsonlLines(text) {
600→    var lines = text.split("\n");
601→    var messages = [];
602→    for (var i = 0; i < lines.length; i++) {
603→      var line = lines[i].trim();
604→      if (!line) continue;
605→      try {
606→        messages.push(JSON.parse(line));
607→      } catch (e) {
608→        // skip malformed
609→      }
610→    }
611→    return messages;
612→  }
613→
614→  // ── Session stats ───────────────────────────────────────────────────────────
615→
616→  function computeStats(messages) {
617→    var stats = {
618→      model: "", apiCalls: 0,
619→      inputTokens: 0, cacheCreation: 0, cacheRead: 0, outputTokens: 0,
620→      peakContext: 0, contextWindow: 200000
621→    };
622→
623→    for (var i = 0; i < messages.length; i++) {
624→      var msg = messages[i];
625→      if (msg.type === "assistant" && msg.message) {
626→        var m = msg.message;
627→        if (m.model && !stats.model) stats.model = m.model;
628→        if (m.usage) {
629→          stats.apiCalls++;
630→          var u = m.usage;
631→          stats.inputTokens += u.input_tokens || 0;
632→          stats.cacheCreation += u.cache_creation_input_tokens || 0;
633→          stats.cacheRead += u.cache_read_input_tokens || 0;
634→          stats.outputTokens += u.output_tokens || 0;
635→          var turnInput = (u.input_tokens || 0) + (u.cache_creation_input_tokens || 0) + (u.cache_read_input_tokens || 0);
636→          if (turnInput > stats.peakContext) stats.peakContext = turnInput;
637→        }
638→      }
639→    }
640→
641→    return stats;
642→  }
643→
644→  function fmtTokens(n) {
645→    if (n >= 1000000) return (n / 1000000).toFixed(1) + "M";
646→    if (n >= 1000) return (n / 1000).toFixed(1) + "K";
647→    return String(n);
648→  }
