 43→
 44→    pre.style.position = "relative";
 45→    var btn = document.createElement("button");
 46→    btn.className = "copy-btn";
 47→    btn.textContent = "Copy";
 48→    btn.addEventListener("click", function () {
 49→      var code = pre.querySelector("code");
