 54→        setTimeout(function () {
 55→          btn.textContent = "Copy";
 56→          btn.classList.remove("copied");
 57→        }, 2000);
 58→      });
 59→    });
 60→    pre.appendChild(btn);
 61→  });
 62→
 63→  // ── Sidebar nav — highlight active user message on scroll ──────────────
 64→  var sidebar = document.getElementById("sidebar");
 65→  if (sidebar) {
 66→    var sidebarLinks = Array.from(sidebar.querySelectorAll(".sidebar-item"));
 67→    var userGroups = sidebarLinks.map(function (link) {
 68→      return document.getElementById(link.getAttribute("data-target"));
 69→    }).filter(Boolean);
 70→
 71→    // Use IntersectionObserver to track which user group is visible
 72→    var currentActive = null;
 73→    var observer = new IntersectionObserver(
 74→      function (entries) {
 75→        entries.forEach(function (entry) {
 76→          if (entry.isIntersecting) {
 77→            var id = entry.target.id;
 78→            if (currentActive) currentActive.classList.remove("active");
 79→            var link = sidebar.querySelector('[data-target="' + id + '"]');
 80→            if (link) {
 81→              link.classList.add("active");
 82→              currentActive = link;
 83→              // Scroll sidebar to keep active item visible
 84→              link.scrollIntoView({ block: "nearest", behavior: "smooth" });
 85→            }
 86→          }
 87→        });
 88→      },
 89→      {
 90→        rootMargin: "-80px 0px -60% 0px",
 91→        threshold: 0
 92→      }
 93→    );
 94→
 95→    userGroups.forEach(function (group) {
 96→      observer.observe(group);
 97→    });
 98→
 99→    // Smooth scroll on sidebar click
100→    sidebarLinks.forEach(function (link) {
101→      link.addEventListener("click", function (e) {
102→        e.preventDefault();
103→        var target = document.getElementById(link.getAttribute("data-target"));
104→        if (target) {
105→          target.scrollIntoView({ behavior: "smooth", block: "start" });
106→        }
107→      });
108→    });
109→  }
110→
111→  // ── Keyboard navigation ─────────────────────────────────────────────────
112→  var groups = Array.from(document.querySelectorAll(".msg-group"));
113→  var currentIdx = -1;
114→
115→  document.addEventListener("keydown", function (e) {
116→    if (e.target.tagName === "INPUT" || e.target.tagName === "TEXTAREA") return;
117→
118→    if (e.key === "j" || e.key === "k") {
119→      e.preventDefault();
120→      if (e.key === "j") {
121→        currentIdx = Math.min(currentIdx + 1, groups.length - 1);
122→      } else {
123→        currentIdx = Math.max(currentIdx - 1, 0);
124→      }
125→      if (groups[currentIdx]) {
126→        groups[currentIdx].scrollIntoView({ behavior: "smooth", block: "start" });
127→      }
128→    }
129→  });
130→})();
