121→function langFromPath(filePath: string): string {
122→  const ext = extname(filePath).toLowerCase();
123→  if (EXT_TO_LANG[ext]) return EXT_TO_LANG[ext];
124→  const base = basename(filePath).toLowerCase();
125→  if (base === "dockerfile") return "dockerfile";
