132→function fileLink(filePath: string, repoUrl: string, commitSha: string): string {
133→  if (!repoUrl) return `<span class="file-path">${esc(filePath)}</span>`;
134→  // Strip leading / or absolute paths — try to make relative to repo root
135→  let rel = filePath;
136→  // Common patterns: /home/runner/work/repo/repo/file or /Users/.../repo/file
137→  const repoName = repoUrl.split("/").pop() || "";
138→  const idx = rel.indexOf(`/${repoName}/`);
139→  if (idx !== -1) {
140→    rel = rel.slice(idx + repoName.length + 2);
141→  } else if (rel.startsWith("/")) {
142→    // Just use basename-ish path for local files
143→    rel = filePath;
144→  }
145→  const url = `${repoUrl}/blob/${commitSha}/${rel}`;
146→  return `<a class="file-link" href="${esc(url)}" target="_blank" rel="noopener">${esc(filePath)}</a>`;
147→}
