155→// ── Diff rendering ─────────────────────────────────────────────────────────────
156→
157→function renderDiff(
158→  oldStr: string,
159→  newStr: string,
160→  filePath: string,
161→  lang?: string
162→): string {
163→  const patch = createTwoFilesPatch(filePath, filePath, oldStr, newStr, "", "");
164→  const lines = patch.split("\n");
165→
166→  // Skip the first two header lines (diff/---)
167→  let startIdx = 0;
168→  for (let i = 0; i < lines.length; i++) {
169→    if (lines[i].startsWith("@@")) {
170→      startIdx = i;
171→      break;
172→    }
173→  }
174→
175→  const out: string[] = [];
176→  let oldLine = 0;
177→  let newLine = 0;
178→
179→  for (let i = startIdx; i < lines.length; i++) {
180→    const line = lines[i];
181→    if (line.startsWith("@@")) {
182→      const match = line.match(/@@ -(\d+)/);
183→      if (match) {
184→        oldLine = parseInt(match[1], 10) - 1;
185→        newLine = oldLine; // approximate
186→      }
187→      const matchNew = line.match(/\+(\d+)/);
188→      if (matchNew) newLine = parseInt(matchNew[1], 10) - 1;
189→      out.push(`<tr class="diff-hunk"><td class="diff-ln"></td><td class="diff-ln"></td><td class="diff-marker"></td><td>${esc(line)}</td></tr>`);
190→    } else if (line.startsWith("+")) {
191→      newLine++;
192→      out.push(
193→        `<tr class="diff-add"><td class="diff-ln"></td><td class="diff-ln">${newLine}</td><td class="diff-marker">+</td><td>${esc(line.slice(1))}</td></tr>`
194→      );
195→    } else if (line.startsWith("-")) {
196→      oldLine++;
197→      out.push(
198→        `<tr class="diff-del"><td class="diff-ln">${oldLine}</td><td class="diff-ln"></td><td class="diff-marker">-</td><td>${esc(line.slice(1))}</td></tr>`
199→      );
200→    } else if (line.startsWith("\\")) {
201→      // "\ No newline at end of file"
202→      continue;
203→    } else {
204→      oldLine++;
205→      newLine++;
206→      out.push(
207→        `<tr class="diff-ctx"><td class="diff-ln">${oldLine}</td><td class="diff-ln">${newLine}</td><td class="diff-marker"> </td><td>${esc(line.slice(1) || "")}</td></tr>`
208→      );
209→    }
210→  }
211→
212→  const langAttr = lang ? ` data-lang="${lang}"` : "";
213→  return `<table class="diff-table"${langAttr}>${out.join("\n")}</table>`;
214→}
