216→// ── Markdown-lite rendering ────────────────────────────────────────────────────
217→
218→function renderMarkdown(text: string): string {
219→  let escaped = esc(text);
220→
221→  // Fenced code blocks: ```lang\n...\n```
222→  escaped = escaped.replace(
223→    /```(\w*)\n([\s\S]*?)```/g,
224→    (_match, lang: string, code: string) => {
225→      const cls = lang ? ` class="language-${lang}"` : "";
226→      return `<pre><code${cls}>${code}</code></pre>`;
227→    }
228→  );
229→
230→  // Inline code
231→  escaped = escaped.replace(/`([^`]+)`/g, "<code>$1</code>");
232→
233→  // Bold
234→  escaped = escaped.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>");
235→
236→  // Line breaks (not inside <pre>)
237→  const parts = escaped.split(/(<pre>[\s\S]*?<\/pre>)/);
238→  for (let i = 0; i < parts.length; i++) {
239→    if (!parts[i].startsWith("<pre>")) {
240→      parts[i] = parts[i].replace(/\n/g, "<br>\n");
241→    }
242→  }
243→
244→  return parts.join("");
245→}
