280→
281→function renderToolUse(
282→  block: ContentBlock,
283→  result: ContentBlock | null,
284→  repoUrl: string,
285→  commitSha: string
286→): string {
287→  const name = block.name || "Unknown";
288→  const inp = (block.input || {}) as Record<string, string>;
289→  const icon = toolIcon(name);
290→
291→  let summaryLabel = "";
292→  let detail = "";
293→
294→  switch (name) {
295→    case "Bash": {
296→      const cmd = inp.command || "";
297→      const desc = inp.description || "";
298→      const firstActionLine = cmd.split("\n").find(l => {
299→        const trimmed = l.trim();
300→        return trimmed && !trimmed.startsWith("#");
301→      }) || cmd.split("\n")[0];
302→      const cmdPreview = firstActionLine.length > 80 ? firstActionLine.slice(0, 80) + "..." : firstActionLine;
303→      summaryLabel = desc
304→        ? `<span class="tool-cmd-preview">${esc(cmdPreview)}</span><span class="tool-desc">${esc(desc)}</span>`
305→        : `<span class="tool-cmd-preview">${esc(cmdPreview)}</span>`;
306→      detail = `<pre><code class="language-bash">${esc(cmd)}</code></pre>`;
307→      break;
308→    }
309→    case "Read": {
310→      const fp = inp.file_path || "";
311→      summaryLabel = shortPath(fp);
312→      detail = `<div class="tool-file-header">${fileLink(fp, repoUrl, commitSha)}</div>`;
313→      break;
314→    }
315→    case "Edit": {
316→      const fp = inp.file_path || "";
317→      const oldStr = inp.old_string || "";
318→      const newStr = inp.new_string || "";
319→      const lang = langFromPath(fp);
320→      const addCount = newStr.split("\n").length;
321→      const delCount = oldStr.split("\n").length;
322→      summaryLabel = `${shortPath(fp)}`;
323→      const badge = `<span class="diff-badge"><span class="diff-badge-add">+${addCount}</span> <span class="diff-badge-del">-${delCount}</span></span>`;
324→      summaryLabel = `${shortPath(fp)} ${badge}`;
325→      detail = `<div class="tool-file-header">${fileLink(fp, repoUrl, commitSha)}</div>`;
326→      if (oldStr || newStr) {
327→        detail += `<div class="diff-container">${renderDiff(oldStr, newStr, fp, lang)}</div>`;
328→      }
329→      break;
330→    }
331→    case "Write": {
332→      const fp = inp.file_path || "";
333→      const content = inp.content || "";
334→      const lang = langFromPath(fp);
335→      const lineCount = content.split("\n").length;
336→      summaryLabel = `${shortPath(fp)} <span class="diff-badge"><span class="diff-badge-add">+${lineCount}</span></span>`;
337→      detail = `<div class="tool-file-header">${fileLink(fp, repoUrl, commitSha)}</div>`;
338→      const displayContent =
339→        content.length > 5000
340→          ? content.slice(0, 5000) + `\n... (${content.length} chars total)`
341→          : content;
342→      const cls = lang ? ` class="language-${lang}"` : "";
343→      detail += `<pre><code${cls}>${esc(displayContent)}</code></pre>`;
344→      break;
345→    }
346→    case "Grep": {
347→      const pattern = inp.pattern || "";
348→      const path = inp.path || "";
349→      summaryLabel = `"${pattern}"${path ? ` in ${shortPath(path)}` : ""}`;
350→      break;
351→    }
352→    case "Glob": {
353→      const pattern = inp.pattern || "";
354→      summaryLabel = pattern;
355→      break;
356→    }
357→    case "Task": {
358→      summaryLabel = (inp.description as string) || "Subagent task";
359→      break;
360→    }
361→    case "AskUserQuestion": {
362→      const questions = (block.input as Record<string, unknown>)?.questions as Array<Record<string, unknown>> | undefined;
363→      if (questions && questions.length > 0) {
364→        const q = questions[0];
365→        summaryLabel = (q.question as string) || "Question";
366→        let questionHtml = `<div class="ask-question">`;
367→        questionHtml += `<div class="ask-question-text">${esc(q.question as string || "")}</div>`;
368→        const options = q.options as Array<Record<string, string>> | undefined;
369→        if (options) {
370→          questionHtml += `<div class="ask-options">`;
371→          for (const opt of options) {
372→            questionHtml += `<div class="ask-option"><span class="ask-option-label">${esc(opt.label || "")}</span>`;
373→            if (opt.description) {
374→              questionHtml += `<span class="ask-option-desc">${esc(opt.description)}</span>`;
375→            }
376→            questionHtml += `</div>`;
377→          }
378→          questionHtml += `</div>`;
379→        }
380→        questionHtml += `</div>`;
381→        detail = questionHtml;
382→      } else {
383→        summaryLabel = "Question";
384→        const inputStr = JSON.stringify(block.input || {}, null, 2);
385→        detail = `<pre><code class="language-json">${esc(inputStr)}</code></pre>`;
386→      }
387→      break;
388→    }
389→    default: {
390→      summaryLabel = name;
391→      const inputStr = JSON.stringify(block.input || {}, null, 2);
392→      if (inputStr !== "{}") {
393→        detail = `<pre><code class="language-json">${esc(inputStr)}</code></pre>`;
394→      }
395→    }
396→  }
397→
398→  // Render the result inline
399→  let resultHtml = "";
400→  if (result) {
401→    const resultContent = extractResultContent(result);
402→    const isError = result.is_error || false;
403→
404→    if (resultContent.trim()) {
405→      const errClass = isError ? " error" : "";
406→      const charCount = resultContent.length;
407→      const displayResult =
408→        resultContent.length > 8000
409→          ? resultContent.slice(0, 8000) + `\n... (${resultContent.length} chars total)`
410→          : resultContent;
411→
412→      // For Read tool, try to syntax-highlight the result
413→      let resultCode = "";
414→      if (name === "Read" && inp.file_path) {
415→        const lang = langFromPath(inp.file_path);
416→        const cls = lang ? ` class="language-${lang}"` : "";
417→        resultCode = `<pre class="tool-result-content${errClass}"><code${cls}>${esc(displayResult)}</code></pre>`;
418→      } else {
419→        resultCode = `<pre class="tool-result-content${errClass}"><code>${esc(displayResult)}</code></pre>`;
420→      }
421→
422→      if (name === "Bash") {
423→        // Bash: show output directly, no collapse
424→        resultHtml = `<div class="tool-result-inline${errClass}"><div class="tool-result-header">${isError ? "Error" : "Output"} <span class="result-size">${charCount.toLocaleString()} chars</span></div>${resultCode}</div>`;
425→      } else {
426→        // Everything else: collapsible
427→        const resultLabel = isError ? "Error" : "Output";
428→        resultHtml = `<details class="tool-result-details${errClass}"><summary class="tool-result-summary">${resultLabel} <span class="result-size">${charCount.toLocaleString()} chars</span></summary>${resultCode}</details>`;
429→      }
430→    }
431→  }
432→
433→  // Don't HTML-escape the summaryLabel since it may contain our badge HTML
434→  const openByDefault = name === "Edit" || name === "Write";
435→  return `<div class="tool-block">
436→<details${openByDefault ? " open" : ""}>
437→<summary class="tool-summary"><span class="tool-icon">${icon}</span><span class="tool-name">${esc(name)}</span><span class="tool-label">${summaryLabel}</span></summary>
438→<div class="tool-detail">${detail}${resultHtml}</div>
439→</details>
440→</div>`;
441→}
442→
443→function extractResultContent(block: ContentBlock): string {
444→  const content = block.content;
445→  if (typeof content === "string") return content;
446→  if (Array.isArray(content)) {
447→    return content
448→      .filter((c) => typeof c === "object" && c.type === "text")
449→      .map((c) => (c as ContentBlock).text || "")
450→      .join("\n");
451→  }
452→  return "";
453→}
454→
455→// ── Build tool result map ──────────────────────────────────────────────────────
456→
457→function buildToolResultMap(messages: SessionMessage[]): ToolResultMap {
458→  const map: ToolResultMap = {};
459→  for (const msg of messages) {
460→    if (msg.type !== "user") continue;
461→    const content = msg.message?.content;
462→    if (!Array.isArray(content)) continue;
463→    for (const block of content) {
464→      if (block.type === "tool_result" && block.tool_use_id) {
465→        map[block.tool_use_id] = block;
466→      }
467→    }
468→  }
469→  return map;
470→}
471→
472→// ── Render thinking ────────────────────────────────────────────────────────────
473→
474→function renderThinking(text: string): string {
475→  const display = text.length > 5000 ? text.slice(0, 5000) + `\n... (${text.length} chars)` : text;
476→  return `<details class="thinking-block"><summary class="thinking-summary"><span class="tool-icon"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg></span>Thinking <span class="result-size">${text.length.toLocaleString()} chars</span></summary><div class="thinking-content">${renderMarkdown(display)}</div></details>`;
477→}
478→
479→// ── Process session ────────────────────────────────────────────────────────────
480→
481→// Render a single message into HTML, returning { role, html } or null if skipped
482→function renderMessage(
483→  msg: SessionMessage,
484→  toolResultMap: ToolResultMap,
485→  repoUrl: string,
486→  commitSha: string,
487→  author: string
488→): { role: "user" | "assistant" | "system"; html: string } | null {
489→  if (
490→    msg.type === "file-history-snapshot" ||
491→    msg.type === "progress" ||
492→    msg.type === "queue-operation" ||
493→    msg.type === "pr-link" ||
494→    msg.isMeta
495→  ) {
496→    return null;
497→  }
498→
499→  if (msg.type === "assistant") {
500→    const content = msg.message?.content;
501→    if (!content) return null;
502→
503→    if (typeof content === "string") {
504→      if (!content.trim()) return null;
505→      return { role: "assistant", html: `<div class="msg-item">${renderMarkdown(content.trim())}</div>` };
506→    }
507→
508→    const parts: string[] = [];
509→    for (const c of content) {
510→      if (c.type === "thinking" && c.thinking) {
511→        parts.push(renderThinking(c.thinking));
512→      } else if (c.type === "text" && c.text?.trim()) {
513→        parts.push(`<div class="msg-text">${renderMarkdown(c.text.trim())}</div>`);
514→      } else if (c.type === "tool_use") {
515→        const result = c.id ? toolResultMap[c.id] || null : null;
516→        parts.push(renderToolUse(c, result, repoUrl, commitSha));
517→      }
518→    }
519→
520→    if (parts.length === 0) return null;
521→    return { role: "assistant", html: `<div class="msg-item">${parts.join("\n")}</div>` };
522→  }
523→
524→  if (msg.type === "user") {
525→    const content = msg.message?.content;
526→    if (!content) return null;
527→
528→    if (typeof content === "string") {
529→      if (content.startsWith("<") && !content.startsWith("<!")) return null;
530→      if (!content.trim()) return null;
531→      return { role: "user", html: `<div class="msg-item">${renderMarkdown(content)}</div>` };
532→    }
533→
534→    const textParts: string[] = [];
535→    for (const c of content) {
536→      if (c.type === "text" && c.text?.trim()) {
537→        if (c.text.startsWith("<local-command") || c.text.startsWith("<command-")) continue;
538→        if (c.text.startsWith("<system-reminder")) continue;
539→        if (c.text.startsWith("<local-command-stdout")) continue;
540→        textParts.push(c.text);
541→      }
542→    }
543→
544→    if (textParts.length === 0) return null;
545→    return { role: "user", html: `<div class="msg-item">${renderMarkdown(textParts.join("\n").trim())}</div>` };
546→  }
547→
548→  if (msg.type === "system") {
549→    const text =
550→      typeof msg.message === "string"
551→        ? msg.message
552→        : typeof msg.message?.content === "string"
553→          ? msg.message.content
554→          : "";
555→    if (text && !text.startsWith("<")) {
556→      return { role: "system", html: `<details class="system-msg"><summary>System</summary><div class="msg-body">${renderMarkdown(text)}</div></details>` };
557→    }
558→  }
559→
560→  return null;
561→}
562→
563→interface UserNavItem {
564→  id: string;
565→  preview: string;
566→  index: number;
567→}
568→
569→function processSession(
570→  messages: SessionMessage[],
571→  repoUrl: string,
572→  commitSha: string,
573→  author: string,
574→  label?: string
575→): { html: string; userNav: UserNavItem[] } {
576→  const toolResultMap = buildToolResultMap(messages);
577→  const output: string[] = [];
578→  const userNav: UserNavItem[] = [];
579→
580→  if (label) {
581→    output.push(`<div class="subagent-label">${esc(label)}</div>`);
582→  }
583→
584→  // Render all messages, then group consecutive same-role messages
585→  const rendered: { role: string; html: string; text: string }[] = [];
586→  for (const msg of messages) {
587→    const r = renderMessage(msg, toolResultMap, repoUrl, commitSha, author);
588→    if (r) {
589→      // Extract plain text preview for user messages
590→      let text = "";
591→      if (r.role === "user") {
592→        const content = msg.message?.content;
593→        if (typeof content === "string") {
594→          text = content.trim();
595→        } else if (Array.isArray(content)) {
596→          for (const c of content) {
597→            if (c.type === "text" && c.text?.trim()) {
598→              if (c.text.startsWith("<")) continue;
599→              text = c.text.trim();
600→              break;
601→            }
602→          }
603→        }
604→      }
605→      rendered.push({ ...r, text });
606→    }
607→  }
608→
609→  // Group consecutive messages by role
610→  let i = 0;
611→  let userGroupIdx = 0;
612→  while (i < rendered.length) {
613→    const role = rendered[i].role;
614→    const groupItems: string[] = [];
615→    let groupText = "";
616→    while (i < rendered.length && rendered[i].role === role) {
617→      groupItems.push(rendered[i].html);
618→      // Skip interrupt markers and very short text for preview
619→      if (!groupText && rendered[i].text && !rendered[i].text.startsWith("[Request interrupted")) {
620→        groupText = rendered[i].text;
621→      }
622→      i++;
623→    }
624→
625→    if (role === "user") {
626→      userGroupIdx++;
627→      const id = `user-msg-${userGroupIdx}`;
628→      const preview = groupText
629→        .replace(/\n/g, " ")
630→        .replace(/\s+/g, " ")
631→        .slice(0, 60)
632→        .trim();
633→      if (preview) {
634→        userNav.push({ id, preview: preview + (groupText.length > 60 ? "..." : ""), index: userGroupIdx });
635→      }
636→      output.push(
637→        `<div id="${id}" class="msg-group user-group"><span class="avatar user-avatar">${esc(author[0].toUpperCase())}</span><div class="msg-group-content">${groupItems.join("\n")}</div></div>`
638→      );
639→    } else if (role === "assistant") {
640→      output.push(
641→        `<div class="msg-group assistant-group"><span class="avatar assistant-avatar">C</span><div class="msg-group-content">${groupItems.join("\n")}</div></div>`
642→      );
643→    } else {
644→      output.push(groupItems.join("\n"));
645→    }
646→  }
647→
648→  return { html: output.join("\n"), userNav };
649→}
650→
651→// ── Load session files ─────────────────────────────────────────────────────────
652→
653→function loadSession(sessionPath: string): {
654→  main: SessionMessage[];
655→  subagents: Map<string, { lines: SessionMessage[]; desc: string }>;
656→} {
657→  const raw = readFileSync(sessionPath, "utf-8");
658→  const main: SessionMessage[] = [];
659→
660→  for (const line of raw.split("\n")) {
661→    if (!line.trim()) continue;
662→    try {
663→      main.push(JSON.parse(line));
664→    } catch {
665→      // skip malformed lines
666→    }
667→  }
668→
669→  const subagents = new Map<string, { lines: SessionMessage[]; desc: string }>();
670→  const sessionDir = sessionPath.replace(/\.jsonl$/, "");
671→  const subagentsDir = join(sessionDir, "subagents");
672→
673→  if (existsSync(subagentsDir)) {
674→    for (const file of readdirSync(subagentsDir).sort()) {
675→      if (!file.endsWith(".jsonl")) continue;
676→      const saLines: SessionMessage[] = [];
677→      const saRaw = readFileSync(join(subagentsDir, file), "utf-8");
678→      for (const line of saRaw.split("\n")) {
679→        if (!line.trim()) continue;
680→        try {
681→          saLines.push(JSON.parse(line));
682→        } catch {
683→          // skip
684→        }
685→      }
686→      const agentId = file.replace(".jsonl", "");
687→      // Try to find a description
688→      let desc = agentId;
689→      for (const sl of saLines) {
690→        if (sl.type === "user" && sl.message?.content) {
691→          const c = sl.message.content;
692→          if (typeof c === "string" && !c.startsWith("<")) {
693→            desc = c.slice(0, 80);
694→            break;
695→          }
696→          if (Array.isArray(c)) {
697→            for (const b of c) {
698→              if (b.type === "text" && b.text && !b.text.startsWith("<")) {
699→                desc = b.text.slice(0, 80);
700→                break;
701→              }
702→            }
703→            if (desc !== agentId) break;
704→          }
705→        }
706→      }
707→      subagents.set(agentId, { lines: saLines, desc });
708→    }
709→  }
710→
711→  return { main, subagents };
712→}
713→
714→// ── Build HTML ─────────────────────────────────────────────────────────────────
715→
