    var groups = Array.from(document.querySelectorAll(".msg-group"));
    var currentIdx = -1;
    document.addEventListener("keydown", function (e) {
      if (e.target.tagName === "INPUT" || e.target.tagName === "TEXTAREA") return;
      if (e.key === "j" || e.key === "k") {
        e.preventDefault();
        if (e.key === "j") {
