    if (resultContent.trim()) {
      var errClass = isError ? " error" : "";
      var charCount = resultContent.length;
      var displayResult = resultContent.length > 8000
        ? resultContent.slice(0, 8000) + "\n... (" + resultContent.length + " chars total)"
