    });
    escaped = escaped.replace(/`([^`]+)`/g, "<code>$1</code>");
    escaped = escaped.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>");
    var parts = escaped.split(/(<pre>[\s\S]*?<\/pre>)/);
    for (var i = 0; i < parts.length; i++) {
      if (!parts[i].startsWith("<pre>")) {
