      } else if (line.startsWith("\\")) {
        continue;
      } else {
        oldLine++; newLine++;
        out.push('<tr class="diff-ctx"><td class="diff-ln">' + oldLine + '</td><td class="diff-ln">' + newLine + '</td><td class="diff-marker"> </td><td>' + esc(line.slice(1) || "") + "</td></tr>");
      }
    }
