---
{
  "attribution": {
    "commit": "",
    "pr": ""
  },
  "model": "opus",
  "env": {
    "CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS": "1"
  },
  "enabledPlugins": {
    "rust-analyzer-lsp@claude-plugins-official": true
  },
  "skipDangerousModePermissionPrompt": true,
  "hooks": {
    "PostToolUse": [
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "command",
            "command": "/tmp/claude-session-test/scripts/attach-session-note.sh",
            "async": true
          }
        ]
      }
    ]
  }
}
---
{
  "permissions": {
    "allow": [
      "Bash(ls:*)",
      "WebSearch",
      "Bash(brew install:*)",
      "Bash(tmux source-file:*)",
      "Bash(ghostty +list-themes:*)",
      "Bash(/Applications/Ghostty.app/Contents/MacOS/ghostty +list-themes:*)",
      "Bash(bat:*)",
      "Bash(which nix:*)",
      "Bash(brew list:*)",
      "Bash(cp:*)",
      "Bash(cd:*)"
    ]
  }
}

