/* Claude Code Session Viewer — client-side renderer + interactivity
 * Supports: text, markdown, tool use, thinking blocks, and inline base64 images */

(function () {
  "use strict";

  // ── URL parsing ─────────────────────────────────────────────────────────────

  var params = new URLSearchParams(window.location.search);
