  1→#!/usr/bin/env tsx
  2→/**
  3→ * Render a Claude Code session JSONL into a standalone HTML page.
  4→ *
  5→ * Usage: tsx render-session.ts <session.jsonl> <commit_sha> [--author <name>] [--repo-url <url>]
  6→ */
  7→
  8→import { readFileSync, readdirSync, existsSync } from "fs";
  9→import { basename, join, extname } from "path";
 10→import { createTwoFilesPatch } from "diff";
