 42→// ── CLI Args ───────────────────────────────────────────────────────────────────
 43→
 44→function parseArgs() {
 45→  const args = process.argv.slice(2);
 46→  const opts: Record<string, string> = {};
 47→  const positional: string[] = [];
 48→
 49→  for (let i = 0; i < args.length; i++) {
 50→    if (args[i].startsWith("--") && i + 1 < args.length) {
 51→      opts[args[i].slice(2)] = args[++i];
 52→    } else {
 53→      positional.push(args[i]);
 54→    }
 55→  }
 56→
 57→  if (positional.length < 2) {
 58→    console.error(
 59→      "Usage: tsx render-session.ts <session.jsonl> <commit_sha> [--author <name>] [--repo-url <url>]"
 60→    );
 61→    process.exit(1);
 62→  }
 63→
 64→  return {
 65→    sessionPath: positional[0],
 66→    commitSha: positional[1],
 67→    author: opts["author"] || "User",
 68→    repoUrl: (opts["repo-url"] || "").replace(/\/$/, ""),
 69→  };
 70→}
