 74→function esc(text: string): string {
 75→  return text
 76→    .replace(/&/g, "&amp;")
 77→    .replace(/</g, "&lt;")
 78→    .replace(/>/g, "&gt;")
 79→    .replace(/"/g, "&quot;");
